let msgOut = {};
let results = msg.payload;

//msgOut.cpu1mLoad = results[0].value;
//msgOut.memTotalKBytes = results[1].value;
//msgOut.memUsedKBytes = results[2].value;
//msgOut.diskUtilPercent = results[3].value;

// กรณี msg.payload เป็น Buffer เช่น <Buffer 30 2e 37 30>
if (Buffer.isBuffer(results[0].value)) {
    results[0].value = results[0].value.toString('ascii'); // แปลงเป็น "0.70"
}

msgOut.cpu1mLoad = parseFloat(results[0].value);
msgOut.memTotalKBytes = results[1].value;
msgOut.memUsedKBytes = results[2].value;
msg.payload = msgOut;


return msg;

// Expects an array of objects from the SNMP node inside msg.payload
const varbinds = msg.payload;
const disks = {};

// 1. Loop through all returned walk metrics and group by their suffix Index
varbinds.forEach(item => {
    const oid = item.oid;
    const value = item.value;

    // Extract the final index number from the OID string
    const match = oid.match(/\.(\d+)$/);
    if (!match) return;
    const index = match[1];

    if (!disks[index]) {
        disks[index] = {};
    }

    // Map OIDs to clean object properties
    if (oid.startsWith("1.3.6.1.2.1.25.2.3.1.3.")) disks[index].descr = value;
    if (oid.startsWith("1.3.6.1.2.1.25.2.3.1.4.")) disks[index].allocUnit = Number(value);
    if (oid.startsWith("1.3.6.1.2.1.25.2.3.1.5.")) disks[index].sizeBlocks = Number(value);
    if (oid.startsWith("1.3.6.1.2.1.25.2.3.1.6.")) disks[index].usedBlocks = Number(value);
});

const calculatedDisks = [];

// 2. Compute true capacities and percentages
for (const index in disks) {
    const d = disks[index];

    // Filter out memory buffers or invalid items that lack standard disk tracking 
    if (d.descr && d.sizeBlocks > 0 && d.allocUnit > 0) {

        if (Buffer.isBuffer(d.descr)) {
            d.descr = d.descr.toString('ascii'); 
        }

        // Skip physical RAM or Virtual memory buffers if you purely want hard drives
        if (d.descr.toUpperCase().includes("MEMORY") 
            || d.descr.includes("run/containerd")
        ) {
            continue; 
        }

        const totalBytes = d.sizeBlocks * d.allocUnit;
        const usedBytes = d.usedBlocks * d.allocUnit;

        const totalGB = (totalBytes / Math.pow(1024, 3)).toFixed(2);
        const usedGB = (usedBytes / Math.pow(1024, 3)).toFixed(2);
        const freeGB = ((totalBytes - usedBytes) / Math.pow(1024, 3)).toFixed(2);
        const utilPercent = ((d.usedBlocks / d.sizeBlocks) * 100).toFixed(1);

        calculatedDisks.push({
            diskIndex: index,
            description: d.descr,
            total_GB: Number(totalGB),
            used_GB: Number(usedGB),
            free_GB: Number(freeGB),
            utilization_percent: Number(utilPercent)
        });

        /*var _totalGB = parseFloat(totalGB)
        var _usedGB = parseFloat(usedGB)
        var _freeGB = parseFloat(freeGB)

        if (Number.isNaN(_totalGB)) { _totalGB =0;}
        if (Number.isNaN(_usedGB)) { _usedGB = 0; }
        if (Number.isNaN(_freeGB)) { _freeGB = 0; }

        msgOut.totalGB += _totalGB;
        msgOut.usedGB += _usedGB;
        msgOut.freeGB += _freeGB;*/
    }
}

// Output the structured disk utilization data array
msg.payload = calculatedDisks;

return msg;
